[
  {
    path: "/",
    element: <Layout />,
    children: [
      { path: "/profile", element: <Profile /> },
      {
        path: "/boards",
        children: [
          { index: true, element: <BoardOverview /> },
          { path: ":id", element: <BoardDetail /> },
        ],
      },
    ],
  },
]

type BoardDetailAction =
  | { type: "UPDATE_BOARD_NAME"; data: string }
  | { type: "ADD_TASK" | "DELETE_TASK" | "UPDATE_TASK"; data: Task }

const [boards, boardsDispatch] = useReducer(
  useBoardOverviewReducer,
  [],
  getBoards,            // Initializer: laedt aus localStorage
)

function handleDragHover(event: React.DragEvent<HTMLDivElement>) {
  const column = event.dataTransfer.getData("column")
  if (isTaskInTasks(column)) {
    setIsDragHover(false)
  } else {
    setIsDragHover(true)
  }
}

const [taskTitle, setTaskTitle] = useState<string>(task.title)
const [taskDescription, setTaskDescription] = useState<string>(
  task.description ?? ""
)
const [date, setDate] = useState<Date | undefined>(
  task.deadline ? new Date(task.deadline) : undefined
)
